module top_module(
    input [31:0] PC4, PC4_imm, correct_PC,
    input [1:0] PCSrc,
    output reg [31:0] PCout
    );always @(PC4 or PC4_imm or correct_PC or PCSrc) begin
        if (PCSrc == 0) PCout = PC4;
        else if (PCSrc == 1) PCout = PC4_imm;
        else PCout = correct_PC;
    end
endmodule
